const swiperHero = new Swiper('.swiper-hero', { loop: !0, pagination: { el: ".swiper-hero__pagination", type: "fraction", renderFraction: function (currentClass, totalClass) { return `<span class="${currentClass} swiper-pagination-box__current"></span>` + `<span class="${totalClass} swiper-pagination-box__total"></span>` } }, autoplay: { delay: 5000, }, allowTouchMove: !1, }); const swiperStory = new Swiper('.swiper-story', { loop: !0, pagination: { el: ".swiper-story__pagination", type: "fraction", renderFraction: function (currentClass, totalClass) { return `<span class="${currentClass} swiper-pagination-box__current"></span>` + `<span class="${totalClass} swiper-pagination-box__total"></span>` } }, spaceBetween: 30, breakpoints: { 992: { slidesPerView: 1.5, spaceBetween: 70, }, }, }); const swiperAbout = new Swiper('.swiper-about', { direction: 'vertical', loop: !0, pagination: { el: ".swiper-about__pagination", type: "fraction", renderFraction: function (currentClass, totalClass) { return '<span class="' + currentClass + '"></span>' + '<span class="' + totalClass + '"></span>' } }, spaceBetween: 30, autoHeight: !0, allowTouchMove: !1, })